import React, { useState } from 'react';

const App = () => {
  const [isLocked, setIsLocked] = useState(true);
  const [success, setSuccess] = useState(false);

  const handleToggle = () => {
    setIsLocked(!isLocked);
    setSuccess(false);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded-md w-96 text-center">
        <h2 className="text-2xl font-bold mb-4">Access Card</h2>
        <button className="bg-[#C06C88] hover:bg-[#411C56] text-white font-bold py-2 px-4 rounded" onClick={handleToggle}>Toggle Lock/Unlock</button>
        {success && <p className="text-green-500 font-bold mt-4">Access granted!</p>}
      </div>
    </div>
  );
};

export default App;
